import os

def is_python_file(filepath):
    """Return True if the filepath has a .py or .pyw extension."""
    ext = os.path.splitext(filepath)[1].lower()
    return ext in ('.py', '.pyw')

def find_common_parent(path1, path2):
    """Return the longest common parent directory of two paths."""
    return os.path.commonpath([path1, path2])

def normalize_path(filepath):
    """Normalize a path by resolving '..' and '.' and removing double separators."""
    return os.path.normpath(filepath)

def relative_to(filepath, base):
    """Return the relative path from base to filepath."""
    return os.path.relpath(filepath, base)
